#include <stdio.h>
int main() {
    int i = 1;
    while (i <= 5) {
        printf("%d\n", i);
        i++;
    }

    // while(1) — infinite loop with break:
    int count = 0;
    while (1) {
        count++;
        if (count >= 5) break;
    }
    printf("%d\n", count); // 5
    return 0;
}

int i = 1;
do {
    printf("%d\n", i);
    i++;
} while (i <= 5);  // ← semicolon!

// Even if condition starts false, runs once:
int x = 100;
do {
    printf("runs once\n");  // prints!
} while (x < 5);

// break:
for(int i=0;i<10;i++){
    if(i==5) break;
    printf("%d ",i);
}
// 0 1 2 3 4

// continue:
for(int i=0;i<8;i++){
    if(i%2!=0) continue;
    printf("%d ",i);
}
// 0 2 4 6

// Legitimate goto use in C:
int* p = malloc(100);
if (!p) goto cleanup;

int* q = malloc(200);
if (!q) goto cleanup;

// ... do work ...

cleanup:
    free(p);
    free(q);
    return -1;

